import{_ as t,o as l,c as r,a2 as o}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"수납 처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/collection.md","filePath":"guide/scenarios/collection.md","lastUpdated":1771991831000}'),e={name:"guide/scenarios/collection.md"};function i(s,a,n,h,c,d){return l(),r("div",null,[...a[0]||(a[0]=[o(`<h1 id="수납-처리" tabindex="-1">수납 처리 <a class="header-anchor" href="#수납-처리" aria-label="Permalink to &quot;수납 처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 20분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 매월 4주차 ~ 익월 1주차</p></blockquote><p>부과된 관리비를 세대별로 수납 처리하고, 회계 전표와 연계하는 전체 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 자동이체 결과 처리   (5분)  → 은행 자동이체 결과 반영</span></span>
<span class="line"><span>2. 개별 수납 처리       (5분)  → 창구·계좌이체 등 개별 건 입력</span></span>
<span class="line"><span>3. 오류 건 처리         (5분)  → 자동수납 오류·미매칭 건 정리</span></span>
<span class="line"><span>4. 수납 전표 연계       (3분)  → 회계 전표 자동 생성</span></span>
<span class="line"><span>5. 수납 결과 확인       (2분)  → 일보·집계표로 최종 확인</span></span></code></pre></div><hr><h2 id="_1단계-자동이체-결과-처리-5분" tabindex="-1">1단계: 자동이체 결과 처리 (5분) <a class="header-anchor" href="#_1단계-자동이체-결과-처리-5분" aria-label="Permalink to &quot;1단계: 자동이체 결과 처리 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/auto-transfer.html">자동이체수납</a></p></blockquote><p>은행에서 받은 자동이체 결과 파일을 시스템에 반영합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>은행에서 자동이체 결과 파일 수신</li><li>자동이체수납 화면 진입</li><li>결과 파일 <strong>업로드</strong></li><li>처리 결과 확인: <ul><li><strong>정상 수납</strong>: 자동 처리 완료</li><li><strong>출금 실패</strong>: 잔액 부족 등 → 미납으로 분류</li><li><strong>이중 출금</strong>: 중복 건 확인 필요</li></ul></li><li><strong>저장</strong> 클릭</li></ol><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 자동이체 결과 파일을 은행에서 수신했는가?</li><li>[ ] 정상 수납 건수와 금액이 예상과 일치하는가?</li><li>[ ] 이중수납(중복 출금) 건이 없는가?</li></ul><hr><h2 id="_2단계-개별-수납-처리-5분" tabindex="-1">2단계: 개별 수납 처리 (5분) <a class="header-anchor" href="#_2단계-개별-수납-처리-5분" aria-label="Permalink to &quot;2단계: 개별 수납 처리 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/process.html">수납처리</a> &gt; 일반수납 (RECP1010)</p></blockquote><p>창구 납부, 계좌이체 등 자동이체 외 수납 건을 처리합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>수납처리 화면 진입</li><li><strong>수납일자</strong>와 <strong>수납기간</strong> 입력</li><li>해당 세대(동·호) 검색</li><li>미납 내역 확인 후 수납 항목 선택</li><li>수납 금액 입력</li><li><strong>처리</strong> 버튼 클릭</li></ol><h3 id="부분-수납이-필요한-경우" tabindex="-1">부분 수납이 필요한 경우 <a class="header-anchor" href="#부분-수납이-필요한-경우" aria-label="Permalink to &quot;부분 수납이 필요한 경우&quot;">​</a></h3><p>세대에서 관리비 전액이 아닌 일부만 납부한 경우:</p><ol><li><strong>부분수납</strong> 모드 선택</li><li>두 가지 방식 중 선택: <ul><li><strong>일반 부분수납</strong>: 체납분 우선 적용 후 나머지 이월</li><li><strong>미납 선택 부분수납</strong>: 특정 미납 건을 선택하여 적용</li></ul></li><li>금액 입력 후 처리</li></ol><div class="tip custom-block"><p class="custom-block-title">수납 취소</p><p>잘못 처리한 수납은 <strong>수납취소</strong> 기능으로 되돌릴 수 있습니다. 수납처리 화면에서 해당 건을 찾아 선택 후 취소를 실행하세요.</p></div><hr><h2 id="_3단계-오류-건-처리-5분" tabindex="-1">3단계: 오류 건 처리 (5분) <a class="header-anchor" href="#_3단계-오류-건-처리-5분" aria-label="Permalink to &quot;3단계: 오류 건 처리 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/process.html">수납처리</a> &gt; 자동수납오류처리 (RECP1020)</p></blockquote><p>자동이체에서 매칭되지 않거나 오류가 발생한 건을 수동으로 정리합니다.</p><h3 id="오류-유형별-처리" tabindex="-1">오류 유형별 처리 <a class="header-anchor" href="#오류-유형별-처리" aria-label="Permalink to &quot;오류 유형별 처리&quot;">​</a></h3><table tabindex="0"><thead><tr><th>오류 유형</th><th>원인</th><th>처리 방법</th></tr></thead><tbody><tr><td>세대 미매칭</td><td>입금자명과 세대정보 불일치</td><td>수동으로 세대 찾아서 매칭</td></tr><tr><td>금액 불일치</td><td>납부 금액 ≠ 부과 금액</td><td>부분수납 처리 또는 차액 확인</td></tr><tr><td>정상 입금인데 미처리</td><td>시스템 자동 매칭 실패</td><td>수동 수납 처리</td></tr><tr><td>가수금 발생</td><td>초과 납부 또는 미확인 입금</td><td>가수금관리(RECP1051)에서 등록</td></tr></tbody></table><h3 id="가수금-처리" tabindex="-1">가수금 처리 <a class="header-anchor" href="#가수금-처리" aria-label="Permalink to &quot;가수금 처리&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/process.html">수납처리</a> &gt; 가수금관리 (RECP1051)</p></blockquote><p>초과 납부나 출처 미확인 입금은 가수금으로 등록해 두고, 이후 확인되면 해당 세대 수납에 적용합니다.</p><div class="warning custom-block"><p class="custom-block-title">30일 이내 처리</p><p>자동수납 오류 건은 <strong>30일 이내에 처리</strong>해야 합니다. 기한을 넘기면 별도의 정산 절차가 필요합니다.</p></div><hr><h2 id="_4단계-수납-전표-연계-3분" tabindex="-1">4단계: 수납 전표 연계 (3분) <a class="header-anchor" href="#_4단계-수납-전표-연계-3분" aria-label="Permalink to &quot;4단계: 수납 전표 연계 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/process.html">수납처리</a> &gt; 수납전표연계 (RECP1023)</p></blockquote><p>수납 내역을 회계 전표로 자동 생성합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>수납전표연계 화면 진입</li><li><strong>수납일자</strong> 선택</li><li><strong>전표</strong> 버튼 클릭 → 회계 전표 자동 생성</li><li>생성된 전표 확인</li></ol><h3 id="출력-양식" tabindex="-1">출력 양식 <a class="header-anchor" href="#출력-양식" aria-label="Permalink to &quot;출력 양식&quot;">​</a></h3><ul><li><strong>복식전표</strong>: 차변/대변 상세 내역</li><li><strong>일계표</strong>: 일별 수납 집계</li><li><strong>수납대장</strong>: 세대별 수납 내역</li></ul><div class="warning custom-block"><p class="custom-block-title">주의</p><p>수납일자가 등록되어 있어야 전표 연계가 가능합니다. 또한, 수납을 취소하면 해당 전표도 영향을 받으므로 주의하세요.</p></div><hr><h2 id="_5단계-수납-결과-확인-2분" tabindex="-1">5단계: 수납 결과 확인 (2분) <a class="header-anchor" href="#_5단계-수납-결과-확인-2분" aria-label="Permalink to &quot;5단계: 수납 결과 확인 (2분)&quot;">​</a></h2><h3 id="일별-확인" tabindex="-1">일별 확인 <a class="header-anchor" href="#일별-확인" aria-label="Permalink to &quot;일별 확인&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/inquiry.html">수납조회</a> &gt; 수납일보 (RECP5030)</p></blockquote><p>날짜를 더블클릭하면 해당 일자의 수납 합계를 확인할 수 있습니다.</p><h3 id="월별-집계" tabindex="-1">월별 집계 <a class="header-anchor" href="#월별-집계" aria-label="Permalink to &quot;월별 집계&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/inquiry.html">수납조회</a> &gt; 수납집계표 (RECP5060)</p></blockquote><p>1개월 이상의 기간을 설정하여 전체 수납 현황을 집계합니다.</p><h3 id="최종-체크리스트" tabindex="-1">최종 체크리스트 <a class="header-anchor" href="#최종-체크리스트" aria-label="Permalink to &quot;최종 체크리스트&quot;">​</a></h3><ul><li>[ ] 자동이체 수납 건수와 금액이 은행 결과와 일치하는가?</li><li>[ ] 오류 건이 모두 처리되었는가?</li><li>[ ] 가수금으로 남아 있는 미확인 입금이 없는가?</li><li>[ ] 수납 전표가 정상 생성되었는가?</li><li>[ ] 수납 합계와 통장 입금 합계가 일치하는가?</li></ul><hr><h2 id="수납일자-은행-변경이-필요할-때" tabindex="-1">수납일자/은행 변경이 필요할 때 <a class="header-anchor" href="#수납일자-은행-변경이-필요할-때" aria-label="Permalink to &quot;수납일자/은행 변경이 필요할 때&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/process.html">수납처리</a> &gt; 수납일자(은행)변경 (RECP1030)</p></blockquote><p>잘못 입력된 수납일자나 은행 정보를 변경할 수 있습니다.</p><ol><li>원래 수납일자 입력</li><li>변경할 일자 또는 은행 선택</li><li>변경 실행</li></ol><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="자동이체-결과가-반영이-안-돼요" tabindex="-1">자동이체 결과가 반영이 안 돼요 <a class="header-anchor" href="#자동이체-결과가-반영이-안-돼요" aria-label="Permalink to &quot;자동이체 결과가 반영이 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 파일 형식 오류 또는 업로드 경로 문제 <strong>해결</strong>: 은행에서 받은 원본 파일이 정확한 형식인지 확인하고, 다시 업로드하세요.</p><h3 id="이미-수납-처리한-건을-다시-수납했어요-이중수납" tabindex="-1">이미 수납 처리한 건을 다시 수납했어요 (이중수납) <a class="header-anchor" href="#이미-수납-처리한-건을-다시-수납했어요-이중수납" aria-label="Permalink to &quot;이미 수납 처리한 건을 다시 수납했어요 (이중수납)&quot;">​</a></h3><p><strong>원인</strong>: 자동이체 + 개별 납부가 동시에 처리된 경우 <strong>해결</strong>: <a href="/recp/auto-transfer.html">자동이체수납</a> &gt; 월별이중수납 메뉴에서 확인하고, 수납취소로 중복 건을 제거하세요.</p><h3 id="수납-전표-연계가-안-돼요" tabindex="-1">수납 전표 연계가 안 돼요 <a class="header-anchor" href="#수납-전표-연계가-안-돼요" aria-label="Permalink to &quot;수납 전표 연계가 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 수납일자가 미등록 상태이거나, 이미 연계 처리된 건 <strong>해결</strong>: 수납일자를 확인하고, 전표관리(ACCT2010)에서 해당 건이 이미 있는지 확인하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/recp/process.html">수납처리</a> - 수납 실행 상세</li><li><a href="/recp/inquiry.html">수납조회</a> - 수납 현황 조회</li><li><a href="/recp/overdue.html">미납조회</a> - 미납 세대 관리</li><li><a href="/recp/auto-transfer.html">자동이체수납</a> - 자동이체 결과</li><li><a href="/acct/voucher.html">전표관리</a> - 수납 전표 확인</li></ul>`,68)])])}const g=t(e,[["render",i]]);export{u as __pageData,g as default};
